function PriceAlert() {
  const [symbol, setSymbol] = React.useState('REPLACE_WITH_SYMBOL');
  const [threshold, setThreshold] = React.useState('REPLACE_WITH_THRESHOLD');
  const [direction, setDirection] = React.useState('below');
  const [type, setType] = React.useState('REPLACE_WITH_TYPE');
  const [price, setPrice] = React.useState(null);
  const [armed, setArmed] = React.useState(false);
  const [fired, setFired] = React.useState(false);
  const [error, setError] = React.useState('');
  React.useEffect(() => {
    if (!armed) return;
    let alive = true;
    const tick = async () => {
      try {
        let p;
        if (type === 'crypto') {
          const r = await fetch(`https://api.coingecko.com/api/v3/simple/price?ids=${encodeURIComponent(symbol.toLowerCase())}&vs_currencies=usd`).then(r=>r.json());
          p = r[symbol.toLowerCase()]?.usd;
        } else {
          const r = await fetch(`https://query1.finance.yahoo.com/v8/finance/chart/${symbol.toUpperCase()}`).then(r=>r.json());
          p = r.chart?.result?.[0]?.meta?.regularMarketPrice;
        }
        if (!alive || typeof p !== 'number') return;
        setPrice(p); setError('');
        const t = parseFloat(threshold);
        const hit = direction === 'below' ? p < t : p > t;
        if (hit && !fired) {
          setFired(true);
          try { await titan.api.call('/api/notify', { method: 'POST', body: { title: 'Price Alert', message: `${symbol} ${direction} ${t}: now ${p}` } }); } catch {}
        }
      } catch (e) { setError(String(e?.message||e)); }
    };
    tick();
    const id = setInterval(tick, 30000);
    return () => { alive = false; clearInterval(id); };
  }, [armed, symbol, threshold, direction, type, fired]);
  return (
    <div style={{padding:14,fontFamily:'system-ui',height:'100%',display:'flex',flexDirection:'column',gap:10}}>
      <div style={{display:'grid',gridTemplateColumns:'1fr 1fr',gap:8}}>
        <input value={symbol} onChange={e=>setSymbol(e.target.value)} placeholder="Symbol" style={{padding:'8px',border:'1px solid #ccc',borderRadius:6}}/>
        <select value={type} onChange={e=>setType(e.target.value)} style={{padding:'8px',border:'1px solid #ccc',borderRadius:6}}><option value="stock">Stock</option><option value="crypto">Crypto</option></select>
        <select value={direction} onChange={e=>setDirection(e.target.value)} style={{padding:'8px',border:'1px solid #ccc',borderRadius:6}}><option value="below">Below</option><option value="above">Above</option></select>
        <input value={threshold} onChange={e=>setThreshold(e.target.value)} placeholder="Price" type="number" style={{padding:'8px',border:'1px solid #ccc',borderRadius:6}}/>
      </div>
      <button onClick={()=>{setArmed(!armed);setFired(false);}} style={{padding:'10px',border:'none',borderRadius:8,background:armed?'#FF3B30':'#34C759',color:'#fff',fontWeight:600,cursor:'pointer'}}>{armed?'Disarm':'Arm Alert'}</button>
      <div style={{textAlign:'center'}}>
        <div style={{fontSize:32,fontWeight:300}}>{price !== null ? `$${Number(price).toLocaleString(undefined,{maximumFractionDigits:4})}` : '—'}</div>
        <div style={{fontSize:12,color:armed?'#34C759':'#888'}}>{armed?(fired?'🔔 Fired!':'Watching…'):'Idle'}</div>
      </div>
      {error && <div style={{color:'#FF3B30',fontSize:12,textAlign:'center'}}>{error}</div>}
    </div>
  );
}
render(<PriceAlert/>);
